  'statement_4f0c1eda_5fed_4d79_8cdd_ac05c377995d',
  'statement_7140fc81_0523_47c6_a23b_c31ede660ea4',
]);

const special = {
  tipo_de_desconto_no_item_1: 'tipo_de_desconto_no_item',
  subtotal_do_item_brl: 'valor_total_do_item_brl',
  subtotal_do_item_usd: 'valor_total_do_item_usd',
};
const requiredUsdBaseFields = [
  'valor_base_saas_categoria_a_b_usd',
  'valor_base_saas_categoria_e_s_usd',
  'valor_base_saas_categoria_espa_os_usd',
  'valor_base_saas_categoria_hospedagem_usd',
  'valor_base_saas_categoria_outros_usd',
];
const upsertFieldValue = (fields, fieldId, fieldValue) => {
  const idx = fields.findIndex((entry) => entry && entry.field_id === fieldId);
  if (idx >= 0) {
    fields[idx] = { ...fields[idx], field_value: fieldValue };
  } else {
    fields.push({ field_id: fieldId, field_value: fieldValue });
  }
};
const isBlankFieldValue = (value) => {
  if (value === undefined || value === null) return true;
  if (Array.isArray(value)) return value.length === 0;
  return typeof value === 'string' ? value.trim() === '' : false;
};

const compStart = String(ctx.run.compStart || '');
const compEnd = String(ctx.run.compEnd || '');
const activePhase = String(ctx.config.activeItemPhaseId || '');
const ruleId = ctx.rule?.ruleId ?? null;
const failureCountBefore = ctx.failures.length;

let totalBrl = 0;
let totalUsd = 0;
const eligibleItems = [];
const createItemRequests = [];

for (const it of inItems) {
  const templateItemId = String(it.templateItemId || '').trim();
  const gqlErrors = Array.isArray(it.errors) ? it.errors : [];

  if (it.error) {
    pushFailure('02.3 | FIN-02 Buscar item template', 'fetch_template_item_error', ruleId, templateItemId || null);
    continue;
  }

  if (gqlErrors.length > 0) {
    pushFailure('02.3 | FIN-02 Buscar item template', 'fetch_template_item_error', ruleId, templateItemId || null);
    continue;
  }

  const card = it.data?.card;
  if (!card || !card.id) {
    pushFailure('02.3 | FIN-02 Buscar item template', 'fetch_template_item_error', ruleId, templateItemId || null);
    continue;
  }

  const phaseId = card.current_phase && card.current_phase.id ? String(card.current_phase.id) : '';
  if (phaseId !== activePhase) {
    continue;
  }

  const fm = fieldMap(card.fields || []);
  const start = String(pickScalar(fm['data_de_in_cio_do_faturamento']) || '').slice(0, 10);
  const end = String(pickScalar(fm['data_de_fim_do_faturamento']) || '').slice(0, 10);

  if (start && start > compEnd) {
    continue;
  }
  if (end && end < compStart) {
    continue;
  }

  const periodicidade = String(pickScalar(fm['periodicidade']) || '').trim();
  let parcelado = null;

  if (periodicidade === 'Parcelado') {
    const pagas = intFrom(pickScalar(fm['parcelas_pagas']));
    const total = intFrom(pickScalar(fm['quantidade_de_parcelas_totais']));

    if (!(total > 0)) {
      pushFailure('02.5 | Consolidar templates e elegibilidade', 'invalid_total_parcelas', ruleId, String(card.id));
      continue;
    }

    if (pagas >= total) {
      continue;
    }

    parcelado = { newParcelasPagas: pagas + 1 };
  }

  const currency = String(pickScalar(fm['moeda_da_fatura']) || '').trim();
  let brl = 0;
  let usd = 0;

  if (currency.startsWith('USD')) {
    usd = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_usd']) ?? pickScalar(fm['subtotal_do_item_usd']));
  } else if (currency.startsWith('BRL')) {
    brl = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_brl']) ?? pickScalar(fm['subtotal_do_item_brl']));
  } else {
    brl = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_brl']) ?? pickScalar(fm['subtotal_do_item_brl']));
    usd = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_usd']) ?? pickScalar(fm['subtotal_do_item_usd']));
  }

  totalBrl += brl;
  totalUsd += usd;

