  const visit = (value) => {
    if (value === undefined || value === null) return;
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    const s = String(value).trim();
    if (s) out.push(s);
  };
  for (const value of values) visit(value);
  return Array.from(new Set(out));
};
const pushFailure = (reason, ...ids) => {
  ctx.failures.push({
    node: SOURCE_NODE,
    reason: String(reason || 'no_created_items_for_invoice'),
    pipefyCardIds: collectIds(...ids),
  });
};
const REQUIRED_FIELD_ERROR_SENTINEL = 'FIN_CREATE_ITEM_REQUIRED_FIELD_ERROR::';
const collectErrorStrings = (value, out = []) => {
